#include<bits/stdc++.h>
using namespace std;
int w[101],v[101],dp[10001];
int main()
{
	int t,n,m;
	scanf("%d%d%d",&t,&n,&m);
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&w[i]);
	}
	t--;
	while(t--)
	{
		for(int i=1;i<=n;i++)
		{
			scanf("%d",&v[i]);
		}
		memset(dp,0,sizeof(dp));
		for(int i=1;i<=n;i++)
		{
			for(int j=w[i];j<=m;j++)
			{
				dp[j]=max(dp[j],dp[j-w[i]]+v[i]-w[i]);;
			}
		}
		m+=dp[m];
		for(int i=1;i<=n;i++)
		{
			w[i]=v[i];
		}
	}
	printf("%d",m);
	return 0;
}
